   677→// Get onboarding summary for recruiter dashboard (candidates with pending docs)
   678→router.get('/recruiter/summary', authMiddleware, async (req, res) => {
   679→  try {
   680→    // Verify user is a recruiter
   681→    if (!req.user.company_id) {
   682→      return res.status(403).json({ error: 'Only recruiters can view onboarding documents' });
   683→    }
   684→
   685→    const result = await pool.query(
   686→      `SELECT
   687→        u.id as candidate_id,
   688→        u.name as candidate_name,
   689→        u.email as candidate_email,
   690→        COUNT(od.id) as total_documents,
   691→        SUM(CASE WHEN od.status = 'completed' OR od.signed_at IS NOT NULL THEN 1 ELSE 0 END) as signed_documents,
   692→        MAX(od.created_at) as last_activity,
   693→        oc.status as checklist_status,
   694→        oc.due_date,
   695→        j.title as job_title,
   696→        cod.wizard_status,
   697→        cod.current_step as wizard_step
   698→      FROM users u
   699→      JOIN offers o ON u.id = o.candidate_id
   700→      LEFT JOIN onboarding_checklists oc ON u.id = oc.candidate_id
   701→      LEFT JOIN onboarding_documents od ON u.id = od.candidate_id
   702→      LEFT JOIN jobs j ON o.job_id = j.id
   703→      LEFT JOIN candidate_onboarding_data cod ON u.id = cod.candidate_id AND cod.checklist_id = oc.id
   704→      WHERE o.company_id = $1 AND o.status IN ('accepted', 'completed')
   705→      GROUP BY u.id, u.name, u.email, oc.status, oc.due_date, j.title, cod.wizard_status, cod.current_step
   706→      ORDER BY u.created_at DESC`,
   707→      [req.user.company_id]
   708→    );
   709→
   710→    // Derive real status from actual document progress (not checklist which may be fake-completed)
   711→    const candidates = result.rows.map(r => {
   712→      const totalDocs = parseInt(r.total_documents) || 0;
   713→      const signedDocs = parseInt(r.signed_documents) || 0;
   714→      let onboarding_status;
   715→
   716→      if (r.wizard_status === 'completed' && totalDocs > 0 && signedDocs === totalDocs) {
   717→        onboarding_status = 'completed';
   718→      } else if (totalDocs > 0 || r.wizard_step > 1) {
   719→        onboarding_status = 'in_progress';
   720→      } else {
   721→        onboarding_status = 'pending';
   722→      }
   723→
   724→      return {
   725→        candidate_id: r.candidate_id,
   726→        candidate_name: r.candidate_name,
   727→        candidate_email: r.candidate_email,
   728→        total_documents: r.total_documents,
   729→        signed_documents: r.signed_documents,
   730→        last_activity: r.last_activity,
   731→        onboarding_status,
   732→        due_date: r.due_date,
   733→        job_title: r.job_title,
   734→        wizard_step: r.wizard_step
   735→      };
   736→    });
   737→
   738→    res.json(candidates);
   739→  } catch (err) {
   740→    console.error('Error fetching onboarding summary:', err);
   741→    res.status(500).json({ error: 'Failed to fetch summary' });
   742→  }
   743→});
