   748→
   749→// Get wizard progress for current candidate
   750→router.get('/wizard/progress', authMiddleware, async (req, res) => {
   751→  try {
   752→    // Get candidate's active checklist
   753→    const checklist = await pool.query(
   754→      `SELECT oc.*, o.title as offer_title, o.company_name, o.salary, o.start_date,
   755→              j.title as job_title
   756→       FROM onboarding_checklists oc
   757→       JOIN offers o ON oc.offer_id = o.id
   758→       LEFT JOIN jobs j ON o.job_id = j.id
   759→       WHERE oc.candidate_id = $1
   760→       ORDER BY oc.created_at DESC LIMIT 1`,
   761→      [req.user.id]
   762→    );
   763→
   764→    if (checklist.rows.length === 0) {
   765→      return res.json({ has_onboarding: false });
   766→    }
   767→
   768→    const cl = checklist.rows[0];
   769→
   770→    // Get or create wizard data
   771→    let wizardData = await pool.query(
   772→      'SELECT * FROM candidate_onboarding_data WHERE candidate_id = $1 AND checklist_id = $2',
   773→      [req.user.id, cl.id]
   774→    );
   775→
   776→    if (wizardData.rows.length === 0) {
   777→      // First time visiting the real wizard — create fresh wizard data
   778→      wizardData = await pool.query(
   779→        `INSERT INTO candidate_onboarding_data (candidate_id, checklist_id)
   780→         VALUES ($1, $2)
   781→         RETURNING *`,
   782→        [req.user.id, cl.id]
   783→      );
   784→
   785→      // If the old fake auto-complete system marked the checklist as "completed"
   786→      // but no real wizard data exists, reset the checklist so the candidate
   787→      // can go through the real flow
   788→      if (cl.status === 'completed' || cl.status === 'in_progress') {
   789→        const existingDocs = await pool.query(
   790→          'SELECT COUNT(*) as cnt FROM onboarding_documents WHERE candidate_id = $1 AND checklist_id = $2',
   791→          [req.user.id, cl.id]
   792→        );
   793→        if (parseInt(existingDocs.rows[0].cnt) === 0) {
   794→          // No real documents = the old system faked it. Reset.
   795→          await pool.query(
   796→            `UPDATE onboarding_checklists SET
   797→              status = 'in_progress',
   798→              completed_items = '[]'::jsonb,
   799→              completed_at = NULL,
   800→              updated_at = NOW()
   801→             WHERE id = $1`,
   802→            [cl.id]
   803→          );
   804→          cl.status = 'in_progress';
   805→          cl.completed_items = [];
   806→        }
   807→      }
   808→    }
   809→
   810→    // Get existing documents
   811→    const documents = await pool.query(
   812→      'SELECT * FROM onboarding_documents WHERE candidate_id = $1 AND checklist_id = $2 ORDER BY created_at',
   813→      [req.user.id, cl.id]
   814→    );
   815→
   816→    res.json({
   817→      has_onboarding: true,
   818→      checklist: cl,
   819→      wizard: wizardData.rows[0],
   820→      documents: documents.rows
   821→    });
   822→  } catch (err) {
   823→    console.error('Error getting wizard progress:', err);
   824→    res.status(500).json({ error: 'Failed to get wizard progress' });
   825→  }
   826→});
