    const offerCompanyId = offer.rows.length > 0 ? offer.rows[0].company_id : null;

    const fullName = [wd.legal_first_name, wd.legal_middle_name, wd.legal_last_name]
      .filter(Boolean).join(' ');

    const documents = [];

    // Generate I-9 Form
